solution: class Solution {
public:
    vector<string> removeInvalidParentheses(string s) {
        vector<string> res;
        unordered_set<string> visited;
        queue<string> q;
        q.push(s);
        visited.insert(s);
        bool found = false;
        while (!q.empty()) {
            string cur = q.front(); q.pop();
            if (isValid(cur)) {
                res.push_back(cur);
                found = true;
            }
            if (found) continue;
            for (int i = 0; i < cur.size(); ++i) {
                if (cur[i] != '(' && cur[i] != ')') continue;
                string next = cur.substr(0, i) + cur.substr(i + 1);
                if (visited.find(next) == visited.end()) {
                    visited.insert(next);
                    q.push(next);
                }
            }
        }
        return res.empty() ? vector<string>{""} : res;
    }
private:
    bool isValid(const string& s) {
        int cnt = 0;
        for (char c : s) {
            if (c == '(') ++cnt;
            else if (c == ')') {
                if (cnt == 0) return false;
                --cnt;
            }
        }
        return cnt == 0;
    }
};
efficiency: HIGH
time complexity: O(2^N * N)
space complexity: O(2^N * N)
energy implications: MEDIUM
explanation: Uses BFS level-order traversal to guarantee the first valid strings found require the minimum removals. Each level represents strings with one more removal; once any valid string is found at a level, no deeper levels are processed. The isValid check is linear per candidate.

